import React, { useState, useEffect, useMemo } from 'react';
import { 
  Calendar, Users, Trash2, 
  RefreshCcw, LogOut, Search, Plus, User, Check, Edit2, Save, X, CheckSquare, Square, Star, Activity, Settings, TrendingUp, Info, UploadCloud, Download
} from 'lucide-react';
import { Service, Booking, Lead, Technician, SystemLog, ServiceCategory, DayAvailability, WeekAvailability } from '../types';
import { db } from '../services/databaseService';
import { INITIAL_SERVICES } from '../constants';

interface AdminDashboardProps {
  onExit: () => void;
  bookings: Booking[];
  leads: Lead[];
  team: Technician[];
  services: Service[];
  logs: SystemLog[];
  setBookings: React.Dispatch<React.SetStateAction<Booking[]>>;
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  updateLocalTeam: (team: Technician[]) => void;
  updateLocalServices: (services: Service[]) => void;
  refreshData: () => Promise<void>;
}

const DEFAULT_AVAILABILITY: WeekAvailability = {
  monday: { isOpen: true, start: "07:00", end: "21:00" },
  tuesday: { isOpen: true, start: "07:00", end: "21:00" },
  wednesday: { isOpen: true, start: "07:00", end: "21:00" },
  thursday: { isOpen: true, start: "07:00", end: "21:00" },
  friday: { isOpen: true, start: "07:00", end: "21:00" },
  saturday: { isOpen: true, start: "07:00", end: "21:00" },
  sunday: { isOpen: false, start: "09:00", end: "17:00" },
};

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  onExit, bookings, leads, team, services, logs, 
  setBookings, setLeads, updateLocalTeam, updateLocalServices, refreshData
}) => {
  const [activeTab, setActiveTab] = useState('services'); // Default to services to match request
  const [searchQuery, setSearchQuery] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [editingMember, setEditingMember] = useState<Technician | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newMember, setNewMember] = useState({ name: '', email: '', calendar_email: '' });
  const [dbStatus, setDbStatus] = useState<'connected' | 'error' | 'checking'>('checking');

  // Service management states
  const [editingService, setEditingService] = useState<Service | null>(null);
  const [isServiceModalOpen, setIsServiceModalOpen] = useState(false);
  const [newService, setNewService] = useState<Partial<Service>>({ category: ServiceCategory.MANICURE, name: '', price: '' });

  useEffect(() => {
    const checkDb = async () => {
      try {
        const stats = await db.getStats();
        setDbStatus(stats ? 'connected' : 'error');
      } catch { setDbStatus('error'); }
    };
    checkDb();
  }, [refreshData]);

  // If DB is connected but empty, we show INITIAL_SERVICES for display.
  // However, we want deletions to be reactive.
  const currentServicesToDisplay = useMemo(() => {
    const filtered = services.length > 0 ? services : INITIAL_SERVICES;
    return filtered.filter(s => 
      s.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      s.category.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [services, searchQuery]);

  const filteredBookings = useMemo(() => bookings.filter(b => 
    b.first_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    b.service.toLowerCase().includes(searchQuery.toLowerCase())
  ), [bookings, searchQuery]);

  const filteredLeads = useMemo(() => leads.filter(l => 
    l.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    l.service.toLowerCase().includes(searchQuery.toLowerCase())
  ), [leads, searchQuery]);

  // Service management actions
  const handleSaveService = async () => {
    if (!newService.name || !newService.price) return;
    setIsProcessing(true);
    const serviceToSave: Service = {
      id: editingService ? editingService.id : `svc-${Math.random().toString(36).substr(2, 9)}`,
      category: newService.category as ServiceCategory,
      name: newService.name,
      price: newService.price
    };
    try {
      await db.saveService(serviceToSave);
      await refreshData();
      setEditingService(null);
      setNewService({ category: ServiceCategory.MANICURE, name: '', price: '' });
      setIsServiceModalOpen(false);
    } catch (err) { console.error(err); } finally { setIsProcessing(false); }
  };

  const handleDeleteService = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!id) return;
    if (!window.confirm("Are you sure you want to delete this service?")) return;

    setIsProcessing(true);
    try {
      // 1. Attempt to delete from database
      await db.deleteService(id);

      // 2. If the service was from INITIAL_SERVICES (mock data) and not yet in DB,
      // we should handle it locally by updating the services state if it was empty.
      if (services.length === 0) {
        // Force the local state to be a copy of INITIAL_SERVICES minus the deleted one
        // so that the UI updates even if nothing was in the DB.
        const updatedMock = INITIAL_SERVICES.filter(s => s.id !== id);
        updateLocalServices(updatedMock);
      } else {
        await refreshData();
      }
    } catch (err) { 
      console.error("Deletion Error:", err); 
    } finally { 
      setIsProcessing(false); 
    }
  };

  const openAddService = (cat?: ServiceCategory) => {
    setEditingService(null);
    setNewService({ category: cat || ServiceCategory.MANICURE, name: '', price: '' });
    setIsServiceModalOpen(true);
  };

  const openEditService = (s: Service) => {
    setEditingService(s);
    setNewService({ category: s.category, name: s.name, price: s.price });
    setIsServiceModalOpen(true);
  };

  const handleAddMember = async () => {
    if (!newMember.name || !newMember.email) return;
    setIsProcessing(true);
    const tech: Technician = {
      id: `tech-${Math.random().toString(36).substr(2, 9)}`,
      name: newMember.name, email: newMember.email, calendar_email: newMember.calendar_email || newMember.email,
      is_synced: true, availability: DEFAULT_AVAILABILITY
    };
    try { 
      await db.saveTeamMember(tech); 
      await refreshData(); 
      setNewMember({ name: '', email: '', calendar_email: '' }); 
      setIsAddModalOpen(false); 
    } catch (error) { console.error(error); } finally { setIsProcessing(false); }
  };

  const handleDeleteMember = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!window.confirm("Delete this technician?")) return;
    setIsProcessing(true);
    try { await db.deleteTeamMember(id); await refreshData(); } catch (error) { console.error(error); } finally { setIsProcessing(false); }
  };

  return (
    <div className="flex h-screen bg-white overflow-hidden text-slate-900 font-sans">
      {/* SIDEBAR */}
      <aside className="w-64 bg-[#0f172a] text-white flex flex-col shrink-0 border-r border-white/5">
        <div className="p-8">
          <span className="text-xl font-bold font-serif italic tracking-tight">Candi Nails <span className="text-pink-500">& Spa</span></span>
        </div>
        <nav className="flex-1 px-4 space-y-1">
          {[
            { id: 'services', label: 'Services', icon: Star },
            { id: 'bookings', label: 'Appointments', icon: Calendar },
            { id: 'leads', label: 'Leads', icon: TrendingUp },
            { id: 'team', label: 'Team', icon: Users },
            { id: 'logs', label: 'Logs', icon: Activity },
          ].map(tab => (
            <button key={tab.id} onClick={() => { setActiveTab(tab.id); setSearchQuery(''); }} className={`w-full flex items-center gap-3 px-5 py-3.5 rounded-xl text-[12px] font-bold transition-all ${activeTab === tab.id ? 'bg-pink-600 text-white shadow-lg' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}>
              <tab.icon size={18} /> {tab.label}
            </button>
          ))}
        </nav>
        <div className="p-6 border-t border-white/5">
          <button onClick={onExit} className="w-full flex items-center gap-3 px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-pink-400 transition-all">
            <LogOut size={16} /> Exit Console
          </button>
        </div>
      </aside>

      {/* MAIN CONTENT */}
      <main className="flex-1 flex flex-col overflow-hidden bg-white">
        {/* HEADER - MATCHING SCREENSHOT */}
        <header className="px-10 py-6 bg-[#0f172a] text-white flex justify-between items-center shrink-0">
          <div>
            <p className="text-[9px] font-black text-pink-500 uppercase tracking-[0.2em] mb-0.5">Management Console</p>
            <h1 className="text-5xl font-bold font-serif tracking-tight">Services</h1>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={() => openAddService()} className="flex items-center gap-2 px-6 py-3 bg-pink-600 hover:bg-pink-700 text-white rounded-xl text-[11px] font-black uppercase tracking-widest transition shadow-md">
              <Plus size={16} /> Add Service
            </button>
            <button onClick={() => refreshData()} className="p-3 border border-white/20 rounded-xl hover:bg-white/10 transition-all text-white">
              <RefreshCcw size={18} className={isProcessing ? 'animate-spin' : ''} />
            </button>
          </div>
        </header>

        {/* SEARCH BAR - MATCHING SCREENSHOT */}
        <div className="px-10 pt-8 pb-4">
          <div className="relative group">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-pink-400 transition-colors" size={20} />
            <input 
              type="text" 
              placeholder="Search..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-14 pr-6 py-4.5 bg-white border border-slate-100 rounded-2xl outline-none focus:border-pink-200 focus:shadow-sm transition-all font-medium text-slate-500 text-sm"
            />
          </div>
        </div>

        {/* CONTENT AREA */}
        <div className="flex-1 overflow-y-auto p-10 bg-white">
          {activeTab === 'services' && (
            <div className="space-y-16">
              {Object.values(ServiceCategory).map(cat => {
                const catServices = currentServicesToDisplay.filter(s => s.category === cat);
                return (
                  <div key={cat} className="space-y-8">
                    <h3 className="text-3xl font-bold font-serif text-[#0f172a] border-b border-slate-50 pb-4">{cat}</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                      {catServices.map(s => (
                        <div key={s.id} className="p-8 bg-white rounded-3xl border border-slate-100 flex justify-between items-center hover:shadow-md hover:border-pink-50 transition-all duration-300 shadow-sm group">
                          <div className="space-y-1">
                            <span className="text-lg font-bold text-[#0f172a] block">{s.name}</span>
                            <div className="text-pink-500 font-bold text-xs uppercase tracking-wider">{s.price}</div>
                          </div>
                          <div className="flex gap-2">
                            <button onClick={() => openEditService(s)} className="p-3 bg-slate-50 text-slate-400 rounded-xl hover:bg-slate-100 hover:text-slate-600 transition-all">
                              <Edit2 size={20} />
                            </button>
                            <button 
                              onClick={(e) => handleDeleteService(s.id, e)} 
                              className="p-3 bg-pink-50 text-pink-400 rounded-xl hover:bg-pink-100 hover:text-pink-600 transition-all"
                            >
                              <Trash2 size={20} />
                            </button>
                          </div>
                        </div>
                      ))}
                      <button onClick={() => openAddService(cat)} className="p-8 rounded-3xl border-2 border-dashed border-slate-100 flex flex-col items-center justify-center gap-2 text-slate-200 hover:border-pink-100 hover:text-pink-300 transition-all group">
                        <Plus size={24} className="group-hover:scale-110 transition-transform" />
                        <span className="font-black uppercase tracking-widest text-[9px]">Add to {cat}</span>
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {activeTab === 'bookings' && (
             <div className="bg-white rounded-3xl border border-slate-100 overflow-hidden">
               <table className="w-full text-left">
                 <thead className="bg-slate-50 border-b border-slate-100 text-[10px] uppercase text-slate-400 font-black tracking-widest">
                   <tr>
                     <th className="px-8 py-6">Client</th>
                     <th className="px-8 py-6">Service</th>
                     <th className="px-8 py-6">Time</th>
                     <th className="px-8 py-6">Tech</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-50">
                   {filteredBookings.map(b => (
                     <tr key={b.id}>
                       <td className="px-8 py-6"><div className="font-bold">{b.first_name}</div><div className="text-xs text-slate-400">{b.phone}</div></td>
                       <td className="px-8 py-6 text-sm font-bold text-pink-600">{b.service}</td>
                       <td className="px-8 py-6 text-sm">{b.date} @ {b.time}</td>
                       <td className="px-8 py-6 text-sm italic">{b.tech}</td>
                     </tr>
                   ))}
                 </tbody>
               </table>
             </div>
          )}

          {activeTab === 'team' && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {team.map(member => (
                <div key={member.id} className="bg-white p-8 rounded-3xl border border-slate-100 flex flex-col items-center text-center shadow-sm">
                  <div className="w-16 h-16 bg-pink-50 rounded-2xl flex items-center justify-center text-pink-400 mb-6">
                    <User size={32} />
                  </div>
                  <h3 className="text-xl font-bold font-serif mb-1">{member.name}</h3>
                  <p className="text-xs text-slate-400 mb-6">{member.email}</p>
                  <div className="flex gap-2 w-full">
                    <button onClick={() => setEditingMember(member)} className="flex-1 py-3 bg-slate-900 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-black transition">Edit Hours</button>
                    <button onClick={(e) => handleDeleteMember(member.id, e)} className="p-3 bg-pink-50 text-pink-400 rounded-xl hover:bg-red-500 hover:text-white transition"><Trash2 size={18} /></button>
                  </div>
                </div>
              ))}
              <button onClick={() => setIsAddModalOpen(true)} className="p-8 rounded-3xl border-2 border-dashed border-slate-100 flex flex-col items-center justify-center gap-3 text-slate-300 hover:border-pink-100 hover:text-pink-400 transition-all">
                <Plus size={32} />
                <span className="font-bold text-[10px] uppercase tracking-widest">Add Staff</span>
              </button>
            </div>
          )}
        </div>
      </main>

      {/* SERVICE MODAL */}
      {isServiceModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-[#0f172a]/70 backdrop-blur-sm p-6">
          <div className="bg-white rounded-[2.5rem] shadow-2xl max-w-lg w-full overflow-hidden p-10 animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-bold font-serif italic text-slate-900">{editingService ? 'Edit Service' : 'New Service'}</h2>
              <button onClick={() => setIsServiceModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-xl transition"><X size={20} /></button>
            </div>
            <div className="space-y-6">
              <div>
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1 mb-2 block">Category</label>
                <select 
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:border-pink-500 transition-colors font-bold"
                  value={newService.category}
                  onChange={(e) => setNewService({ ...newService, category: e.target.value as ServiceCategory })}
                >
                  {Object.values(ServiceCategory).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
              <div>
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1 mb-2 block">Name</label>
                <input type="text" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:border-pink-500 transition-colors font-bold" value={newService.name} onChange={(e) => setNewService({...newService, name: e.target.value})} />
              </div>
              <div>
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1 mb-2 block">Price Range</label>
                <input type="text" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:border-pink-500 transition-colors font-bold" value={newService.price} onChange={(e) => setNewService({...newService, price: e.target.value})} />
              </div>
            </div>
            <button onClick={handleSaveService} disabled={isProcessing} className="w-full mt-10 bg-pink-600 text-white py-4.5 rounded-xl font-black text-[11px] uppercase tracking-widest hover:bg-pink-700 transition shadow-lg">
              {editingService ? 'Update Service' : 'Add Service'}
            </button>
          </div>
        </div>
      )}

      {/* STAFF MODAL */}
      {isAddModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-[#0f172a]/70 backdrop-blur-sm p-6">
          <div className="bg-white rounded-[2.5rem] shadow-2xl max-w-md w-full p-10">
            <h2 className="text-2xl font-bold font-serif mb-8">Add Staff</h2>
            <div className="space-y-6">
              <input type="text" placeholder="Name" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl outline-none font-bold" value={newMember.name} onChange={(e) => setNewMember({...newMember, name: e.target.value})} />
              <input type="email" placeholder="Email" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl outline-none font-bold" value={newMember.email} onChange={(e) => setNewMember({...newMember, email: e.target.value})} />
            </div>
            <div className="flex gap-4 mt-10">
              <button onClick={() => setIsAddModalOpen(false)} className="flex-1 py-4 text-slate-500 font-bold uppercase text-[10px] tracking-widest">Cancel</button>
              <button onClick={handleAddMember} disabled={isProcessing} className="flex-1 py-4 bg-pink-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest">Add</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { User, Mic, Send, X, Sparkles, CircleCheck, AlertTriangle, RefreshCcw, Loader2 } from 'lucide-react';
import { 
  startLiveSession, 
  generateChatResponse, 
  base64ToUint8Array, 
  decodeAudioData, 
  floatToPcm 
} from '../services/geminiService';
import { BUSINESS_INFO } from '../constants';
import { Technician } from '../types';

interface AIAgentProps {
  onAdminAuth: (phrase: string) => void;
  onNewBooking: (booking: any) => void;
  onNewLead: (lead: any) => void;
  team?: Technician[];
}

const BookingConfirmationModal = ({ booking, onConfirm, onCancel }: { booking: any, onConfirm: () => void, onCancel: () => void }) => (
  <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md">
    <div className="bg-white rounded-[3rem] shadow-2xl max-w-md w-full overflow-hidden animate-in fade-in zoom-in duration-300">
      <div className="p-10">
        <div className="flex justify-between items-start mb-8">
          <div className="p-4 bg-green-50 rounded-3xl text-green-500 shadow-sm border border-green-100">
            <CircleCheck size={32} />
          </div>
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition"><X size={20} /></button>
        </div>
        <h2 className="text-3xl font-bold mb-4 font-serif text-slate-900">Confirm Booking</h2>
        <div className="bg-slate-50 p-6 rounded-3xl space-y-4 mb-8 text-sm border border-slate-100">
          <div className="grid grid-cols-2 gap-y-6 gap-x-4">
            <div>
              <p className="text-slate-400 uppercase tracking-widest text-[9px] font-black mb-1">Name</p>
              <p className="font-bold text-slate-800">{booking.first_name}</p>
            </div>
            <div>
              <p className="text-slate-400 uppercase tracking-widest text-[9px] font-black mb-1">Nail tech</p>
              <p className="font-bold text-slate-800">{booking.tech}</p>
            </div>
            <div className="col-span-2">
              <p className="text-slate-400 uppercase tracking-widest text-[9px] font-black mb-1">Service</p>
              <p className="font-bold text-slate-800">{booking.service}</p>
            </div>
            <div className="col-span-2">
              <p className="text-slate-400 uppercase tracking-widest text-[9px] font-black mb-1">Appointment</p>
              <p className="font-bold text-slate-800">{booking.date} at {booking.time}</p>
            </div>
          </div>
        </div>
        <button onClick={onConfirm} className="w-full bg-pink-600 text-white py-5 rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-pink-700 transition shadow-xl shadow-pink-100">All Correct</button>
      </div>
    </div>
  </div>
);

const AIAgent: React.FC<AIAgentProps> = ({ onAdminAuth, onNewBooking, onNewLead, team = [] }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isVoiceMode, setIsVoiceMode] = useState(true);
  const [messages, setMessages] = useState<any[]>([]);
  const [inputText, setInputText] = useState("");
  const [isConnecting, setIsConnecting] = useState(false);
  const [isAgentSpeaking, setIsAgentSpeaking] = useState(false);
  const [showConfirmModal, setShowConfirmModal] = useState(false);
  const [pendingBooking, setPendingBooking] = useState<any>({});
  const [errorState, setErrorState] = useState<string | null>(null);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const microphoneStreamRef = useRef<MediaStream | null>(null);
  const processorNodeRef = useRef<ScriptProcessorNode | null>(null);
  const sourceNodeRef = useRef<MediaStreamAudioSourceNode | null>(null);

  const nextStartTimeRef = useRef(0);
  const activeSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const userTranscriptionRef = useRef("");
  const modelTranscriptionRef = useRef("");
  const chatHistoryRef = useRef<any[]>([]);
  const isVoiceActiveRef = useRef(true);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const isSessionLiveRef = useRef(false);
  const isPendingTerminationRef = useRef(false);
  const isPendingBookingModalRef = useRef(false);

  const teamNames = team.map(t => t.name);

  useEffect(() => { chatHistoryRef.current = messages; }, [messages]);
  useEffect(() => { isVoiceActiveRef.current = isVoiceMode; }, [isVoiceMode]);

  const stopAllAudio = useCallback(() => {
    activeSourcesRef.current.forEach(s => { try { s.stop(); } catch {} });
    activeSourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  }, []);

  const cleanupAudioNodes = useCallback(() => {
    isSessionLiveRef.current = false;
    if (processorNodeRef.current) { processorNodeRef.current.disconnect(); processorNodeRef.current = null; }
    if (sourceNodeRef.current) { sourceNodeRef.current.disconnect(); sourceNodeRef.current = null; }
    if (microphoneStreamRef.current) { microphoneStreamRef.current.getTracks().forEach(track => track.stop()); microphoneStreamRef.current = null; }
  }, []);

  const closeSession = useCallback(() => {
    setIsAgentSpeaking(false);
    stopAllAudio();
    cleanupAudioNodes();
    isPendingTerminationRef.current = false;
    isPendingBookingModalRef.current = false;
    if (sessionPromiseRef.current) {
      sessionPromiseRef.current.then(s => { try { s.close(); } catch {} });
      sessionPromiseRef.current = null;
    }
    setIsOpen(false);
  }, [stopAllAudio, cleanupAudioNodes]);

  const checkSecretPhrase = useCallback((text: string) => {
    const normalized = text.toLowerCase().replace(/[^\w\s]/g, "").replace(/\s+/g, " ").trim();
    const secret = BUSINESS_INFO.adminPhrase.toLowerCase().replace(/[^\w\s]/g, "").replace(/\s+/g, " ").trim();
    if (normalized.includes(secret)) {
      onAdminAuth(BUSINESS_INFO.adminPhrase);
      closeSession();
    }
  }, [onAdminAuth, closeSession]);

  const addMessage = useCallback((role: 'user' | 'agent', text: string) => {
    if (!text.trim()) return;
    const newMessage = { id: Math.random().toString(36), role, text, timestamp: new Date() };
    setMessages(prev => [...prev, newMessage]);
    checkSecretPhrase(text);
  }, [checkSecretPhrase]);

  const startSession = async () => {
    setErrorState(null);
    setIsConnecting(true);
    isPendingTerminationRef.current = false;
    isPendingBookingModalRef.current = false;
    isSessionLiveRef.current = false;
    cleanupAudioNodes();

    try {
      const streamPromise = navigator.mediaDevices.getUserMedia({ audio: true });
      if (!inputAudioContextRef.current) inputAudioContextRef.current = new AudioContext({ sampleRate: 16000 });
      if (!outputAudioContextRef.current) outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });

      const sessionPromise = startLiveSession({
        onopen: async () => {
          try {
            const stream = await streamPromise;
            microphoneStreamRef.current = stream;
            setIsConnecting(false);
            setIsAgentSpeaking(true);
            isSessionLiveRef.current = true;
            const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
            sourceNodeRef.current = source;
            const processor = inputAudioContextRef.current!.createScriptProcessor(1024, 1, 1);
            processorNodeRef.current = processor;
            processor.onaudioprocess = (e) => {
              if (!isSessionLiveRef.current || !isVoiceActiveRef.current) return;
              try {
                const pcmBlob = floatToPcm(e.inputBuffer.getChannelData(0));
                sessionPromise.then((session) => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              } catch (err) {
                isSessionLiveRef.current = false;
              }
            };
            source.connect(processor);
            processor.connect(inputAudioContextRef.current!.destination);
            sessionPromise.then((session) => {
              session.sendRealtimeInput({ text: "CONVERSATION_START: Please state your official opening statement." });
            });
          } catch (micErr) {
            setErrorState("Microphone access denied.");
            setIsConnecting(false);
            cleanupAudioNodes();
          }
        },
        onmessage: async (msg: any) => {
          if (msg.toolCall) {
            for (const fc of msg.toolCall.functionCalls) {
              if (fc.name === "requestBookingConfirmation") {
                setPendingBooking({ ...fc.args, toolCallId: fc.id });
                if (activeSourcesRef.current.size === 0) { setShowConfirmModal(true); setIsAgentSpeaking(false); }
                else { isPendingBookingModalRef.current = true; }
              } else if (fc.name === "terminateSession") {
                if (activeSourcesRef.current.size === 0) closeSession();
                else isPendingTerminationRef.current = true;
              }
            }
          }

          const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (audioData && outputAudioContextRef.current && isVoiceActiveRef.current) {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContextRef.current.currentTime);
            const buffer = await decodeAudioData(base64ToUint8Array(audioData), outputAudioContextRef.current, 24000, 1);
            const source = outputAudioContextRef.current.createBufferSource();
            source.buffer = buffer;
            source.connect(outputAudioContextRef.current.destination);
            source.addEventListener('ended', () => { 
              activeSourcesRef.current.delete(source);
              if (isPendingBookingModalRef.current && activeSourcesRef.current.size === 0) {
                isPendingBookingModalRef.current = false; setShowConfirmModal(true); setIsAgentSpeaking(false);
              }
              if (isPendingTerminationRef.current && activeSourcesRef.current.size === 0) setTimeout(closeSession, 200);
            });
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += buffer.duration;
            activeSourcesRef.current.add(source);
          }

          if (msg.serverContent?.interrupted) stopAllAudio();

          if (msg.serverContent?.inputTranscription) {
            const partialText = msg.serverContent.inputTranscription.text;
            userTranscriptionRef.current += partialText;
            checkSecretPhrase(userTranscriptionRef.current);
          }

          if (msg.serverContent?.outputTranscription) modelTranscriptionRef.current += msg.serverContent.outputTranscription.text;

          if (msg.serverContent?.turnComplete) {
            if (userTranscriptionRef.current) { addMessage('user', userTranscriptionRef.current); userTranscriptionRef.current = ""; }
            if (modelTranscriptionRef.current) { addMessage('agent', modelTranscriptionRef.current); modelTranscriptionRef.current = ""; }
          }
        },
        onerror: () => { setErrorState("AI Service unavailable."); setIsConnecting(false); cleanupAudioNodes(); },
        onclose: () => { isSessionLiveRef.current = false; setIsConnecting(false); cleanupAudioNodes(); }
      }, teamNames);
      sessionPromiseRef.current = sessionPromise;
    } catch (err) {
      setErrorState("Failed to connect.");
      setIsConnecting(false);
      cleanupAudioNodes();
    }
  };

  const toggleOpen = () => { if (isOpen) closeSession(); else { setIsOpen(true); setIsVoiceMode(true); startSession(); } };

  const handleChatSubmit = async () => {
    if (!inputText.trim()) return;
    const msg = inputText; setInputText(""); addMessage('user', msg);
    if (isVoiceMode) { setIsVoiceMode(false); stopAllAudio(); cleanupAudioNodes(); }
    try {
      const response = await generateChatResponse(msg, chatHistoryRef.current, teamNames);
      addMessage('agent', response.text);
    } catch (err) { addMessage('agent', "I'm having trouble connecting."); }
  };

  const handleModalConfirm = async () => {
    onNewBooking(pendingBooking);
    setShowConfirmModal(false);
    if (sessionPromiseRef.current && pendingBooking.toolCallId) {
      sessionPromiseRef.current.then((session) => {
        session.sendToolResponse({ functionResponses: [{ id: pendingBooking.toolCallId, name: "requestBookingConfirmation", response: { result: "Success." } }] });
      });
    } else { addMessage('agent', "Perfect! Appointment booked."); }
  };

  return (
    <>
      <div className="fixed bottom-8 right-8 z-[60]">
        <button 
          onClick={toggleOpen}
          className={`w-20 h-20 rounded-full flex items-center justify-center transition-all duration-500 shadow-2xl relative group ${isOpen ? 'bg-slate-900 text-white rotate-90' : 'bg-pink-500 text-white hover:scale-110 hover:shadow-pink-200'}`}
        >
          {isOpen ? <X size={32} /> : <Mic size={32} className="group-hover:animate-pulse" />}
          {!isOpen && <div className="absolute -top-1 -right-1 w-6 h-6 bg-white rounded-full flex items-center justify-center animate-bounce shadow-md"><Sparkles size={12} className="text-pink-500" /></div>}
        </button>
      </div>

      {isOpen && (
        <div className="fixed inset-0 md:inset-auto md:bottom-32 md:right-8 z-[60] w-full md:w-[450px] md:h-[700px] bg-white md:rounded-[3rem] shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-12 duration-500 border border-pink-50">
          <div className="p-8 bg-slate-900 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-pink-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-pink-500/20">
                {isVoiceMode ? <Mic size={24} className={isAgentSpeaking ? 'animate-pulse' : ''} /> : <Sparkles size={24} />}
              </div>
              <div>
                <h3 className="font-bold text-lg font-serif italic">Candi's AI Assistant</h3>
                <div className="flex items-center gap-1.5">
                  <div className={`w-1.5 h-1.5 rounded-full ${isConnecting ? 'bg-amber-400 animate-pulse' : 'bg-green-400'}`}></div>
                  <span className="text-[9px] uppercase tracking-widest text-slate-400 font-bold">{isConnecting ? 'Connecting...' : 'Active Now'}</span>
                </div>
              </div>
            </div>
            <button onClick={closeSession} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl transition text-slate-400 hover:text-white">
              <X size={20} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/50 custom-scrollbar">
            {messages.length === 0 && !isConnecting && (
              <div className="text-center py-10 space-y-4">
                <div className="w-16 h-16 bg-pink-100 text-pink-500 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Sparkles size={32} />
                </div>
                <h4 className="text-slate-800 font-bold font-serif italic text-xl">How can I help you, Love?</h4>
                <p className="text-slate-400 text-xs max-w-[200px] mx-auto leading-relaxed">I can book appointments, answer beauty questions, or help with salon info.</p>
              </div>
            )}

            {isConnecting && (
              <div className="flex flex-col items-center justify-center h-full space-y-4">
                <Loader2 className="w-8 h-8 text-pink-500 animate-spin" />
                <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Syncing Voice...</p>
              </div>
            )}

            {messages.map((m) => (
              <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[85%] p-5 rounded-[2rem] text-sm font-medium leading-relaxed ${
                  m.role === 'user' 
                    ? 'bg-pink-600 text-white rounded-tr-none shadow-lg shadow-pink-200' 
                    : 'bg-white text-slate-700 rounded-tl-none shadow-sm border border-slate-100'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
          </div>

          {errorState && (
            <div className="px-8 py-3 bg-red-50 border-t border-red-100 flex items-center gap-3 text-red-500 text-[10px] font-bold uppercase tracking-wider">
              <AlertTriangle size={14} /> {errorState}
              <button onClick={startSession} className="ml-auto underline">Retry</button>
            </div>
          )}

          <div className="p-6 bg-white border-t border-slate-100 shrink-0">
            <div className="relative flex items-center gap-3">
              <input 
                type="text"
                placeholder="Type a message..."
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleChatSubmit()}
                className="flex-1 bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-sm outline-none focus:border-pink-200 transition-all font-medium pr-14"
              />
              <button 
                onClick={handleChatSubmit}
                disabled={!inputText.trim()}
                className="absolute right-2 p-2.5 bg-pink-600 text-white rounded-xl hover:bg-pink-700 transition disabled:opacity-50 disabled:grayscale shadow-md"
              >
                <Send size={18} />
              </button>
            </div>
            <div className="mt-4 flex justify-between items-center px-1">
               <button 
                  onClick={() => setIsVoiceMode(!isVoiceMode)}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.1em] transition-colors ${isVoiceMode ? 'text-pink-600' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  <div className={`w-2 h-2 rounded-full ${isVoiceMode ? 'bg-pink-600 animate-pulse' : 'bg-slate-300'}`}></div>
                  {isVoiceMode ? 'Voice Mode Active' : 'Enable Voice'}
                </button>
                <span className="text-[9px] text-slate-300 font-bold uppercase tracking-widest">Powered by Gemini 2.5</span>
            </div>
          </div>
        </div>
      )}

      {showConfirmModal && (
        <BookingConfirmationModal 
          booking={pendingBooking} 
          onConfirm={handleModalConfirm} 
          onCancel={() => setShowConfirmModal(false)} 
        />
      )}
    </>
  );
};

export default AIAgent;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Calendar, Users, Trash2, 
  RefreshCcw, LogOut, Search, Plus, User, Check, Edit2, Save, X, Star, Activity, TrendingUp
} from 'lucide-react';
import { Service, Booking, Lead, Technician, SystemLog, ServiceCategory, WeekAvailability } from '../types';
import { db } from '../services/databaseService';
import { INITIAL_SERVICES } from '../constants';

interface AdminDashboardProps {
  onExit: () => void;
  bookings: Booking[];
  leads: Lead[];
  team: Technician[];
  services: Service[];
  logs: SystemLog[];
  setBookings: React.Dispatch<React.SetStateAction<Booking[]>>;
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  updateLocalTeam: (team: Technician[]) => void;
  updateLocalServices: (services: Service[]) => void;
  refreshData: () => Promise<void>;
}

const DEFAULT_AVAILABILITY: WeekAvailability = {
  monday: { isOpen: true, start: "07:00", end: "21:00" },
  tuesday: { isOpen: true, start: "07:00", end: "21:00" },
  wednesday: { isOpen: true, start: "07:00", end: "21:00" },
  thursday: { isOpen: true, start: "07:00", end: "21:00" },
  friday: { isOpen: true, start: "07:00", end: "21:00" },
  saturday: { isOpen: true, start: "07:00", end: "21:00" },
  sunday: { isOpen: false, start: "09:00", end: "17:00" },
};

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  onExit, bookings, leads, team, services, logs, 
  setBookings, setLeads, updateLocalTeam, updateLocalServices, refreshData
}) => {
  const [activeTab, setActiveTab] = useState('services');
  const [searchQuery, setSearchQuery] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [editingService, setEditingService] = useState<Service | null>(null);
  const [isServiceModalOpen, setIsServiceModalOpen] = useState(false);
  const [newService, setNewService] = useState<Partial<Service>>({ category: ServiceCategory.MANICURE, name: '', price: '' });
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newMember, setNewMember] = useState({ name: '', email: '', calendar_email: '' });

  const currentServicesToDisplay = useMemo(() => {
    const filtered = services.length > 0 ? services : INITIAL_SERVICES;
    return filtered.filter(s => 
      s.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      s.category.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [services, searchQuery]);

  const filteredBookings = useMemo(() => bookings.filter(b => 
    b.first_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    b.service.toLowerCase().includes(searchQuery.toLowerCase())
  ), [bookings, searchQuery]);

  const filteredLeads = useMemo(() => leads.filter(l => 
    l.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    l.service.toLowerCase().includes(searchQuery.toLowerCase())
  ), [leads, searchQuery]);

  const handleSaveService = async () => {
    if (!newService.name || !newService.price) return;
    setIsProcessing(true);
    const serviceToSave: Service = {
      id: editingService ? editingService.id : `svc-${Math.random().toString(36).substr(2, 9)}`,
      category: newService.category as ServiceCategory,
      name: newService.name,
      price: newService.price
    };
    try {
      await db.saveService(serviceToSave);
      await refreshData();
      setIsServiceModalOpen(false);
      setEditingService(null);
    } catch (err) { console.error(err); } finally { setIsProcessing(false); }
  };

  const handleDeleteService = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    if (!window.confirm("Delete this service?")) return;
    setIsProcessing(true);
    try {
      await db.deleteService(id);
      if (services.length === 0) {
        updateLocalServices(INITIAL_SERVICES.filter(s => s.id !== id));
      } else {
        await refreshData();
      }
    } catch (err) { console.error(err); } finally { setIsProcessing(false); }
  };

  const openAddService = (cat?: ServiceCategory) => {
    setEditingService(null);
    setNewService({ category: cat || ServiceCategory.MANICURE, name: '', price: '' });
    setIsServiceModalOpen(true);
  };

  const openEditService = (s: Service) => {
    setEditingService(s);
    setNewService({ category: s.category, name: s.name, price: s.price });
    setIsServiceModalOpen(true);
  };

  const handleAddMember = async () => {
    if (!newMember.name || !newMember.email) return;
    setIsProcessing(true);
    const tech: Technician = {
      id: `tech-${Math.random().toString(36).substr(2, 9)}`,
      name: newMember.name, email: newMember.email, calendar_email: newMember.email,
      is_synced: true, availability: DEFAULT_AVAILABILITY
    };
    try { 
      await db.saveTeamMember(tech); 
      await refreshData(); 
      setIsAddModalOpen(false); 
    } catch (error) { console.error(error); } finally { setIsProcessing(false); }
  };

  const handleDeleteMember = async (id: string) => {
    if (!window.confirm("Delete staff member?")) return;
    setIsProcessing(true);
    try { await db.deleteTeamMember(id); await refreshData(); } catch (error) { console.error(error); } finally { setIsProcessing(false); }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden text-slate-900 font-sans">
      {/* SIDEBAR */}
      <aside className="w-64 bg-white border-r border-slate-200 flex flex-col shrink-0">
        <div className="p-8">
          <span className="text-xl font-bold font-serif italic tracking-tight text-slate-900">Candi Nails <span className="text-pink-500">& Spa</span></span>
        </div>
        <nav className="flex-1 px-4 space-y-1">
          {[
            { id: 'services', label: 'Services', icon: Star },
            { id: 'bookings', label: 'Bookings', icon: Calendar },
            { id: 'leads', label: 'Leads', icon: TrendingUp },
            { id: 'team', label: 'Our Team', icon: Users },
            { id: 'logs', label: 'System Logs', icon: Activity },
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id)} className={`w-full flex items-center gap-3 px-5 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === tab.id ? 'bg-pink-50 text-pink-600 shadow-sm' : 'text-slate-500 hover:text-slate-900 hover:bg-slate-50'}`}>
              <tab.icon size={18} /> {tab.label}
            </button>
          ))}
        </nav>
        <div className="p-6 border-t border-slate-100">
          <button onClick={onExit} className="w-full flex items-center gap-3 px-5 py-3 rounded-xl text-xs font-bold text-slate-400 hover:text-pink-600 transition-all">
            <LogOut size={16} /> Exit Console
          </button>
        </div>
      </aside>

      {/* MAIN CONTENT */}
      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="px-10 py-6 bg-white border-b border-slate-200 flex justify-between items-center shrink-0">
          <h1 className="text-2xl font-bold font-serif text-slate-900 capitalize">{activeTab} Management</h1>
          <div className="flex items-center gap-3">
            <button onClick={() => refreshData()} className="p-2.5 text-slate-400 hover:text-slate-900 transition-all">
              <RefreshCcw size={18} className={isProcessing ? 'animate-spin' : ''} />
            </button>
            <button onClick={() => activeTab === 'services' ? openAddService() : setIsAddModalOpen(true)} className="flex items-center gap-2 px-5 py-2.5 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-slate-800 transition">
              <Plus size={16} /> Add New
            </button>
          </div>
        </header>

        {/* SEARCH & FILTERS */}
        <div className="px-10 py-4 bg-white border-b border-slate-100">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input type="text" placeholder="Search entries..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full pl-12 pr-6 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 ring-pink-500/10 transition-all text-sm font-medium" />
          </div>
        </div>

        {/* CONTENT AREA */}
        <div className="flex-1 overflow-y-auto p-10">
          {activeTab === 'services' && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {currentServicesToDisplay.map(s => (
                <div key={s.id} className="p-6 bg-white rounded-2xl border border-slate-200 hover:shadow-md transition-all group">
                  <div className="flex justify-between items-start mb-4">
                    <span className="px-3 py-1 bg-slate-100 text-[9px] font-black uppercase tracking-widest text-slate-500 rounded-full">{s.category}</span>
                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => openEditService(s)} className="p-2 text-slate-400 hover:text-pink-600"><Edit2 size={16} /></button>
                      <button onClick={(e) => handleDeleteService(s.id, e)} className="p-2 text-slate-400 hover:text-red-500"><Trash2 size={16} /></button>
                    </div>
                  </div>
                  <h3 className="font-bold text-slate-900 text-lg mb-1">{s.name}</h3>
                  <p className="text-pink-600 font-bold text-sm">{s.price}</p>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'bookings' && (
             <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
               <table className="w-full text-left">
                 <thead className="bg-slate-50 border-b border-slate-200 text-[10px] uppercase text-slate-400 font-black tracking-widest">
                   <tr>
                     <th className="px-8 py-4">Client</th>
                     <th className="px-8 py-4">Service</th>
                     <th className="px-8 py-4">Appointment</th>
                     <th className="px-8 py-4">Tech</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                   {filteredBookings.map(b => (
                     <tr key={b.id} className="hover:bg-slate-50/50 transition-colors">
                       <td className="px-8 py-4 text-sm font-bold text-slate-900">{b.first_name}</td>
                       <td className="px-8 py-4 text-sm text-pink-600 font-medium">{b.service}</td>
                       <td className="px-8 py-4 text-sm text-slate-600">{b.date} @ {b.time}</td>
                       <td className="px-8 py-4 text-sm text-slate-400 italic">{b.tech}</td>
                     </tr>
                   ))}
                 </tbody>
               </table>
             </div>
          )}

          {activeTab === 'team' && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {team.map(member => (
                <div key={member.id} className="bg-white p-8 rounded-2xl border border-slate-200 flex flex-col items-center text-center">
                  <div className="w-14 h-14 bg-pink-50 rounded-2xl flex items-center justify-center text-pink-500 mb-4">
                    <User size={28} />
                  </div>
                  <h3 className="text-lg font-bold text-slate-900">{member.name}</h3>
                  <p className="text-xs text-slate-400 mb-6">{member.email}</p>
                  <button onClick={() => handleDeleteMember(member.id)} className="text-xs font-bold text-red-400 hover:text-red-600 uppercase tracking-widest">Remove</button>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      {/* MODALS */}
      {isServiceModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-3xl shadow-2xl max-w-md w-full p-10 animate-in zoom-in duration-200">
            <h2 className="text-xl font-bold font-serif mb-8">{editingService ? 'Edit' : 'New'} Service</h2>
            <div className="space-y-6">
              <input type="text" placeholder="Service Name" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-sm" value={newService.name} onChange={(e) => setNewService({...newService, name: e.target.value})} />
              <input type="text" placeholder="Price (e.g. $40-$50)" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-sm" value={newService.price} onChange={(e) => setNewService({...newService, price: e.target.value})} />
            </div>
            <div className="flex gap-3 mt-10">
              <button onClick={() => setIsServiceModalOpen(false)} className="flex-1 py-4 text-slate-400 font-bold uppercase text-[10px] tracking-widest">Cancel</button>
              <button onClick={handleSaveService} className="flex-1 py-4 bg-slate-900 text-white rounded-xl font-bold text-[10px] uppercase tracking-widest">Save</button>
            </div>
          </div>
        </div>
      )}

      {isAddModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-3xl shadow-2xl max-w-md w-full p-10">
            <h2 className="text-xl font-bold font-serif mb-8">Add Staff</h2>
            <div className="space-y-6">
              <input type="text" placeholder="Staff Name" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-sm" value={newMember.name} onChange={(e) => setNewMember({...newMember, name: e.target.value})} />
              <input type="email" placeholder="Email Address" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-sm" value={newMember.email} onChange={(e) => setNewMember({...newMember, email: e.target.value})} />
            </div>
            <div className="flex gap-3 mt-10">
              <button onClick={() => setIsAddModalOpen(false)} className="flex-1 py-4 text-slate-400 font-bold uppercase text-[10px] tracking-widest">Cancel</button>
              <button onClick={handleAddMember} className="flex-1 py-4 bg-pink-600 text-white rounded-xl font-bold text-[10px] uppercase tracking-widest">Add Member</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { User, Mic, Send, X, Sparkles, CircleCheck, AlertTriangle, RefreshCcw, Loader2 } from 'lucide-react';
import { 
  startLiveSession, 
  generateChatResponse, 
  base64ToUint8Array, 
  decodeAudioData, 
  floatToPcm 
} from '../services/geminiService';
import { BUSINESS_INFO } from '../constants';
import { Technician } from '../types';

interface AIAgentProps {
  onAdminAuth: (phrase: string) => void;
  onNewBooking: (booking: any) => void;
  onNewLead: (lead: any) => void;
  team?: Technician[];
}

const BookingConfirmationModal = ({ booking, onConfirm, onCancel }: { booking: any, onConfirm: () => void, onCancel: () => void }) => (
  <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md">
    <div className="bg-white rounded-[3rem] shadow-2xl max-w-md w-full overflow-hidden animate-in fade-in zoom-in duration-300">
      <div className="p-10">
        <div className="flex justify-between items-start mb-8">
          <div className="p-4 bg-green-50 rounded-3xl text-green-500 shadow-sm border border-green-100">
            <CircleCheck size={32} />
          </div>
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition"><X size={20} /></button>
        </div>
        <h2 className="text-3xl font-bold mb-4 font-serif text-slate-900">Confirm Booking</h2>
        <div className="bg-slate-50 p-6 rounded-3xl space-y-4 mb-8 text-sm border border-slate-100">
          <div className="grid grid-cols-2 gap-y-6 gap-x-4">
            <div>
              <p className="text-slate-400 uppercase tracking-widest text-[9px] font-black mb-1">Name</p>
              <p className="font-bold text-slate-800">{booking.first_name}</p>
            </div>
            <div>
              <p className="text-slate-400 uppercase tracking-widest text-[9px] font-black mb-1">Nail tech</p>
              <p className="font-bold text-slate-800">{booking.tech}</p>
            </div>
            <div className="col-span-2">
              <p className="text-slate-400 uppercase tracking-widest text-[9px] font-black mb-1">Service</p>
              <p className="font-bold text-slate-800">{booking.service}</p>
            </div>
            <div className="col-span-2">
              <p className="text-slate-400 uppercase tracking-widest text-[9px] font-black mb-1">Appointment</p>
              <p className="font-bold text-slate-800">{booking.date} at {booking.time}</p>
            </div>
          </div>
        </div>
        <button onClick={onConfirm} className="w-full bg-pink-600 text-white py-5 rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-pink-700 transition shadow-xl shadow-pink-100">All Correct</button>
      </div>
    </div>
  </div>
);

const AIAgent: React.FC<AIAgentProps> = ({ onAdminAuth, onNewBooking, onNewLead, team = [] }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isVoiceMode, setIsVoiceMode] = useState(true);
  const [messages, setMessages] = useState<any[]>([]);
  const [inputText, setInputText] = useState("");
  const [isConnecting, setIsConnecting] = useState(false);
  const [isAgentSpeaking, setIsAgentSpeaking] = useState(false);
  const [showConfirmModal, setShowConfirmModal] = useState(false);
  const [pendingBooking, setPendingBooking] = useState<any>({});
  const [errorState, setErrorState] = useState<string | null>(null);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const microphoneStreamRef = useRef<MediaStream | null>(null);
  const processorNodeRef = useRef<ScriptProcessorNode | null>(null);
  const sourceNodeRef = useRef<MediaStreamAudioSourceNode | null>(null);

  const nextStartTimeRef = useRef(0);
  const activeSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const userTranscriptionRef = useRef("");
  const modelTranscriptionRef = useRef("");
  const chatHistoryRef = useRef<any[]>([]);
  const isVoiceActiveRef = useRef(true);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const isSessionLiveRef = useRef(false);
  const isPendingTerminationRef = useRef(false);
  const isPendingBookingModalRef = useRef(false);

  const teamNames = team.map(t => t.name);

  useEffect(() => { chatHistoryRef.current = messages; }, [messages]);
  useEffect(() => { isVoiceActiveRef.current = isVoiceMode; }, [isVoiceMode]);

  const stopAllAudio = useCallback(() => {
    activeSourcesRef.current.forEach(s => { try { s.stop(); } catch {} });
    activeSourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  }, []);

  const cleanupAudioNodes = useCallback(() => {
    isSessionLiveRef.current = false;
    if (processorNodeRef.current) { processorNodeRef.current.disconnect(); processorNodeRef.current = null; }
    if (sourceNodeRef.current) { sourceNodeRef.current.disconnect(); sourceNodeRef.current = null; }
    if (microphoneStreamRef.current) { microphoneStreamRef.current.getTracks().forEach(track => track.stop()); microphoneStreamRef.current = null; }
  }, []);

  const closeSession = useCallback(() => {
    setIsAgentSpeaking(false);
    stopAllAudio();
    cleanupAudioNodes();
    isPendingTerminationRef.current = false;
    isPendingBookingModalRef.current = false;
    if (sessionPromiseRef.current) {
      sessionPromiseRef.current.then(s => { try { s.close(); } catch {} });
      sessionPromiseRef.current = null;
    }
    setIsOpen(false);
  }, [stopAllAudio, cleanupAudioNodes]);

  const checkSecretPhrase = useCallback((text: string) => {
    const normalized = text.toLowerCase().replace(/[^\w\s]/g, "").replace(/\s+/g, " ").trim();
    const secret = BUSINESS_INFO.adminPhrase.toLowerCase().replace(/[^\w\s]/g, "").replace(/\s+/g, " ").trim();
    if (normalized.includes(secret)) {
      onAdminAuth(BUSINESS_INFO.adminPhrase);
      closeSession();
    }
  }, [onAdminAuth, closeSession]);

  const addMessage = useCallback((role: 'user' | 'agent', text: string) => {
    if (!text.trim()) return;
    const newMessage = { id: Math.random().toString(36), role, text, timestamp: new Date() };
    setMessages(prev => [...prev, newMessage]);
    checkSecretPhrase(text);
  }, [checkSecretPhrase]);

  const renderMessageText = (text: string) => {
    return text.split('\n').map((line, i) => {
      const parts = line.split(/(\*\*.*?\*\*)/g).map((part, j) => 
        part.startsWith('**') && part.endsWith('**') 
          ? <strong key={j} className="font-bold text-inherit">{part.slice(2, -2)}</strong> 
          : part
      );

      return (
        <div key={i} className={`min-h-[1.2em] ${line.trim().startsWith('-') ? 'pl-2' : ''}`}>
          {parts}
        </div>
      );
    });
  };

  const startSession = async () => {
    setErrorState(null);
    setIsConnecting(true);
    isPendingTerminationRef.current = false;
    isPendingBookingModalRef.current = false;
    isSessionLiveRef.current = false;
    cleanupAudioNodes();

    try {
      const streamPromise = navigator.mediaDevices.getUserMedia({ audio: true });
      if (!inputAudioContextRef.current) inputAudioContextRef.current = new AudioContext({ sampleRate: 16000 });
      if (!outputAudioContextRef.current) outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });

      const sessionPromise = startLiveSession({
        onopen: async () => {
          try {
            const stream = await streamPromise;
            microphoneStreamRef.current = stream;
            setIsConnecting(false);
            setIsAgentSpeaking(true);
            isSessionLiveRef.current = true;
            const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
            sourceNodeRef.current = source;
            const processor = inputAudioContextRef.current!.createScriptProcessor(1024, 1, 1);
            processorNodeRef.current = processor;
            processor.onaudioprocess = (e) => {
              if (!isSessionLiveRef.current || !isVoiceActiveRef.current) return;
              try {
                const pcmBlob = floatToPcm(e.inputBuffer.getChannelData(0));
                sessionPromise.then((session) => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              } catch (err) {
                isSessionLiveRef.current = false;
              }
            };
            source.connect(processor);
            processor.connect(inputAudioContextRef.current!.destination);
            sessionPromise.then((session) => {
              session.sendRealtimeInput({ text: "CONVERSATION_START: Please state your official opening statement." });
            });
          } catch (micErr) {
            setErrorState("Microphone access denied.");
            setIsConnecting(false);
            cleanupAudioNodes();
          }
        },
        onmessage: async (msg: any) => {
          if (msg.toolCall) {
            for (const fc of msg.toolCall.functionCalls) {
              if (fc.name === "requestBookingConfirmation") {
                setPendingBooking({ ...fc.args, toolCallId: fc.id });
                if (activeSourcesRef.current.size === 0) { setShowConfirmModal(true); setIsAgentSpeaking(false); }
                else { isPendingBookingModalRef.current = true; }
              } else if (fc.name === "terminateSession") {
                if (activeSourcesRef.current.size === 0) closeSession();
                else isPendingTerminationRef.current = true;
              }
            }
          }

          const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (audioData && outputAudioContextRef.current && isVoiceActiveRef.current) {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContextRef.current.currentTime);
            const buffer = await decodeAudioData(base64ToUint8Array(audioData), outputAudioContextRef.current, 24000, 1);
            const source = outputAudioContextRef.current.createBufferSource();
            source.buffer = buffer;
            source.connect(outputAudioContextRef.current.destination);
            source.addEventListener('ended', () => { 
              activeSourcesRef.current.delete(source);
              if (isPendingBookingModalRef.current && activeSourcesRef.current.size === 0) {
                isPendingBookingModalRef.current = false; setShowConfirmModal(true); setIsAgentSpeaking(false);
              }
              if (isPendingTerminationRef.current && activeSourcesRef.current.size === 0) setTimeout(closeSession, 200);
            });
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += buffer.duration;
            activeSourcesRef.current.add(source);
          }

          if (msg.serverContent?.interrupted) stopAllAudio();

          if (msg.serverContent?.inputTranscription) {
            const partialText = msg.serverContent.inputTranscription.text;
            userTranscriptionRef.current += partialText;
            checkSecretPhrase(userTranscriptionRef.current);
          }

          if (msg.serverContent?.outputTranscription) modelTranscriptionRef.current += msg.serverContent.outputTranscription.text;

          if (msg.serverContent?.turnComplete) {
            if (userTranscriptionRef.current) { addMessage('user', userTranscriptionRef.current); userTranscriptionRef.current = ""; }
            if (modelTranscriptionRef.current) { addMessage('agent', modelTranscriptionRef.current); modelTranscriptionRef.current = ""; }
          }
        },
        onerror: () => { setErrorState("AI Service unavailable."); setIsConnecting(false); cleanupAudioNodes(); },
        onclose: () => { isSessionLiveRef.current = false; setIsConnecting(false); cleanupAudioNodes(); }
      }, teamNames);
      sessionPromiseRef.current = sessionPromise;
    } catch (err) {
      setErrorState("Failed to connect.");
      setIsConnecting(false);
      cleanupAudioNodes();
    }
  };

  const toggleOpen = () => { if (isOpen) closeSession(); else { setIsOpen(true); setIsVoiceMode(true); startSession(); } };

  const handleChatSubmit = async () => {
    if (!inputText.trim()) return;
    const msg = inputText; setInputText(""); addMessage('user', msg);
    if (isVoiceMode) { setIsVoiceMode(false); stopAllAudio(); cleanupAudioNodes(); }
    try {
      const response = await generateChatResponse(msg, chatHistoryRef.current, teamNames);
      addMessage('agent', response.text);
    } catch (err) { addMessage('agent', "I'm having trouble connecting."); }
  };

  const handleModalConfirm = async () => {
    onNewBooking(pendingBooking);
    setShowConfirmModal(false);
    if (sessionPromiseRef.current && pendingBooking.toolCallId) {
      sessionPromiseRef.current.then((session) => {
        session.sendToolResponse({ functionResponses: [{ id: pendingBooking.toolCallId, name: "requestBookingConfirmation", response: { result: "Success." } }] });
      });
    } else { addMessage('agent', "Perfect! Appointment booked."); }
  };

  return (
    <>
      <div className="fixed bottom-8 right-8 z-[60] flex flex-col items-end gap-2">
        {!isOpen && (
          <div className="bg-white px-5 py-2.5 rounded-2xl rounded-br-sm shadow-xl border border-pink-100 animate-in slide-in-from-bottom-4 fade-in duration-700 mb-1 relative group cursor-pointer" onClick={toggleOpen}>
             <p className="font-serif italic font-bold text-slate-800 text-sm whitespace-nowrap pr-1">Hey Love ✨</p>
          </div>
        )}
        <button 
          onClick={toggleOpen}
          className={`w-20 h-20 rounded-full flex items-center justify-center transition-all duration-500 shadow-2xl relative group ${isOpen ? 'bg-slate-900 text-white rotate-90' : 'bg-pink-500 text-white hover:scale-110 hover:shadow-pink-200'}`}
        >
          {isOpen ? <X size={32} /> : <Mic size={32} className="group-hover:animate-pulse" />}
        </button>
      </div>

      {isOpen && (
        <div className="fixed inset-0 md:inset-auto md:bottom-32 md:right-8 z-[60] w-full md:w-[450px] md:h-[700px] bg-white md:rounded-[3rem] shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-12 duration-500 border border-pink-50">
          <div className="p-8 bg-slate-900 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-pink-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-pink-500/20">
                {isVoiceMode ? <Mic size={24} className={isAgentSpeaking ? 'animate-pulse' : ''} /> : <Sparkles size={24} />}
              </div>
              <div>
                <h3 className="font-bold text-lg font-serif italic">Candi's AI Assistant</h3>
                <div className="flex items-center gap-1.5">
                  <div className={`w-1.5 h-1.5 rounded-full ${isConnecting ? 'bg-amber-400 animate-pulse' : 'bg-green-400'}`}></div>
                  <span className="text-[9px] uppercase tracking-widest text-slate-400 font-bold">{isConnecting ? 'Connecting...' : 'Active Now'}</span>
                </div>
              </div>
            </div>
            <button onClick={closeSession} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl transition text-slate-400 hover:text-white">
              <X size={20} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/50 custom-scrollbar">
            {messages.length === 0 && !isConnecting && (
              <div className="text-center py-10 space-y-4">
                <div className="w-16 h-16 bg-pink-100 text-pink-500 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Sparkles size={32} />
                </div>
                <h4 className="text-slate-800 font-bold font-serif italic text-xl">How can I help you, Love?</h4>
                <p className="text-slate-400 text-xs max-w-[200px] mx-auto leading-relaxed">I can book appointments, answer beauty questions, or help with salon info.</p>
              </div>
            )}

            {isConnecting && (
              <div className="flex flex-col items-center justify-center h-full space-y-4">
                <Loader2 className="w-8 h-8 text-pink-500 animate-spin" />
                <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Syncing Voice...</p>
              </div>
            )}

            {messages.map((m) => (
              <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[85%] p-5 rounded-[2rem] text-sm font-medium leading-relaxed ${
                  m.role === 'user' 
                    ? 'bg-pink-600 text-white rounded-tr-none shadow-lg shadow-pink-200' 
                    : 'bg-white text-slate-700 rounded-tl-none shadow-sm border border-slate-100'
                }`}>
                  {renderMessageText(m.text)}
                </div>
              </div>
            ))}
          </div>

          {errorState && (
            <div className="px-8 py-3 bg-red-50 border-t border-red-100 flex items-center gap-3 text-red-500 text-[10px] font-bold uppercase tracking-wider">
              <AlertTriangle size={14} /> {errorState}
              <button onClick={startSession} className="ml-auto underline">Retry</button>
            </div>
          )}

          <div className="p-6 bg-white border-t border-slate-100 shrink-0">
            <div className="relative flex items-center gap-3">
              <input 
                type="text"
                placeholder="Type a message..."
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleChatSubmit()}
                className="flex-1 bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-sm outline-none focus:border-pink-200 transition-all font-medium pr-14"
              />
              <button 
                onClick={handleChatSubmit}
                disabled={!inputText.trim()}
                className="absolute right-2 p-2.5 bg-pink-600 text-white rounded-xl hover:bg-pink-700 transition disabled:opacity-50 disabled:grayscale shadow-md"
              >
                <Send size={18} />
              </button>
            </div>
            <div className="mt-4 flex justify-between items-center px-1">
               <button 
                  onClick={() => setIsVoiceMode(!isVoiceMode)}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.1em] transition-colors ${isVoiceMode ? 'text-pink-600' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  <div className={`w-2 h-2 rounded-full ${isVoiceMode ? 'bg-pink-600 animate-pulse' : 'bg-slate-300'}`}></div>
                  {isVoiceMode ? 'Voice Mode Active' : 'Enable Voice'}
                </button>
                <span className="text-[9px] text-slate-300 font-bold uppercase tracking-widest">Powered by Gemini 2.5</span>
            </div>
          </div>
        </div>
      )}

      {showConfirmModal && (
        <BookingConfirmationModal 
          booking={pendingBooking} 
          onConfirm={handleModalConfirm} 
          onCancel={() => setShowConfirmModal(false)} 
        />
      )}
    </>
  );
};

export default AIAgent;

