  const processorNodeRef = useRef<ScriptProcessorNode | null>(null);
  const sourceNodeRef = useRef<MediaStreamAudioSourceNode | null>(null);

  const nextStartTimeRef = useRef(0);
  const activeSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const userTranscriptionRef = useRef("");
  const modelTranscriptionRef = useRef("");
  const chatHistoryRef = useRef<any[]>([]);
  const isVoiceActiveRef = useRef(true);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const isSessionLiveRef = useRef(false);
  const isPendingTerminationRef = useRef(false);
  const isPendingBookingModalRef = useRef(false);

  const teamNames = team.map(t => t.name);

  useEffect(() => { chatHistoryRef.current = messages; }, [messages]);
  useEffect(() => { isVoiceActiveRef.current = isVoiceMode; }, [isVoiceMode]);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isConnecting, isAgentSpeaking]);

  const stopAllAudio = useCallback(() => {
    activeSourcesRef.current.forEach(s => { try { s.stop(); } catch {} });
    activeSourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  }, []);

  const cleanupAudioNodes = useCallback(() => {
    isSessionLiveRef.current = false;
    if (processorNodeRef.current) { 
      try { processorNodeRef.current.disconnect(); } catch {}
      processorNodeRef.current = null; 
    }
    if (sourceNodeRef.current) { 
      try { sourceNodeRef.current.disconnect(); } catch {}
      sourceNodeRef.current = null; 
    }
    if (microphoneStreamRef.current) { 
      microphoneStreamRef.current.getTracks().forEach(track => track.stop()); 
      microphoneStreamRef.current = null; 
    }
  }, []);

  const closeSession = useCallback(() => {
    setIsAgentSpeaking(false);
    stopAllAudio();
    cleanupAudioNodes();
    isPendingTerminationRef.current = false;
    isPendingBookingModalRef.current = false;

    if (sessionPromiseRef.current) {
      sessionPromiseRef.current.then(s => { try { s.close(); } catch {} });
      sessionPromiseRef.current = null;
    }
    setIsOpen(false);
  }, [stopAllAudio, cleanupAudioNodes]);

  const checkSecretPhrase = useCallback((text: string) => {
    const normalized = text.toLowerCase().replace(/[^\w\s]/g, "").replace(/\s+/g, " ").trim();
    const secret = BUSINESS_INFO.adminPhrase.toLowerCase().replace(/[^\w\s]/g, "").replace(/\s+/g, " ").trim();
    if (normalized.includes(secret)) {
      onAdminAuth(BUSINESS_INFO.adminPhrase);
      closeSession();
    }
  }, [onAdminAuth, closeSession]);

  const addMessage = useCallback((role: 'user' | 'agent', text: string) => {
    if (!text.trim()) return;
    const newMessage = { id: Math.random().toString(36), role, text, timestamp: new Date() };
    setMessages(prev => [...prev, newMessage]);
    checkSecretPhrase(text);
  }, [checkSecretPhrase]);

  const renderMessageText = (text: string) => {
    return text.split('\n').map((line, i) => {
      const parts = line.split(/(\*\*.*?\*\*)/g).map((part, j) => 
        part.startsWith('**') && part.endsWith('**') 
          ? <strong key={j} className="font-bold text-inherit">{part.slice(2, -2)}</strong> 
          : part
      );

      return (
        <div key={i} className={`min-h-[1.2em] ${line.trim().startsWith('-') ? 'pl-2' : ''}`}>
          {parts}
        </div>
      );
    });
  };

  const startSession = async () => {
    setErrorState(null);
    setIsConnecting(true);
    isPendingTerminationRef.current = false;
    isPendingBookingModalRef.current = false;
    isSessionLiveRef.current = false;
    cleanupAudioNodes();

    try {
      // Initiate mic stream first
      const streamPromise = navigator.mediaDevices.getUserMedia({ audio: true });

      if (!inputAudioContextRef.current) inputAudioContextRef.current = new AudioContext({ sampleRate: 16000 });
      if (!outputAudioContextRef.current) outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });

      // Start the Gemini session
      const sessionPromise = startLiveSession({
        onopen: async () => {
          try {
            const stream = await streamPromise;

            // Check if session was closed while waiting for mic
            if (!sessionPromiseRef.current) {
               stream.getTracks().forEach(t => t.stop());
               return;
            }

            microphoneStreamRef.current = stream;
            setIsConnecting(false);
            setIsAgentSpeaking(true);
            isSessionLiveRef.current = true;

            const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
            sourceNodeRef.current = source;
            const processor = inputAudioContextRef.current!.createScriptProcessor(1024, 1, 1);
            processorNodeRef.current = processor;

            processor.onaudioprocess = (e) => {
              if (!isSessionLiveRef.current || !isVoiceActiveRef.current) return;
              try {
                const inputData = e.inputBuffer.getChannelData(0);
                const pcmBlob = floatToPcm(inputData);

                sessionPromise.then((session) => {
                  if (!isSessionLiveRef.current) return;
                  // Handle potential send errors if socket closed unexpectedly
                  session.sendRealtimeInput({ media: pcmBlob }).catch(err => {
                    console.debug("Send error, preventing spam:", err);
                    isSessionLiveRef.current = false;
                    cleanupAudioNodes(); // Stop processing immediately
                  });
                });
              } catch (err) {
                isSessionLiveRef.current = false;
              }
            };

            source.connect(processor);
            processor.connect(inputAudioContextRef.current!.destination);

            sessionPromise.then((session) => {
              session.sendRealtimeInput({ text: "CONVERSATION_START: Please state your official opening statement." });
            });
          } catch (micErr) {
            console.error("Mic error:", micErr);
            setErrorState("Microphone access denied.");
            setIsConnecting(false);
            cleanupAudioNodes();
          }
        },
        onmessage: async (msg: any) => {
          if (msg.toolCall) {
            for (const fc of msg.toolCall.functionCalls) {
              if (fc.name === "requestBookingConfirmation") {
                setPendingBooking({ ...fc.args, toolCallId: fc.id });
                // Immediate popup and pause audio
                stopAllAudio();
                setShowConfirmModal(true); 
                setIsAgentSpeaking(false); 
              } else if (fc.name === "terminateSession") {
                isPendingTerminationRef.current = true;
                if (activeSourcesRef.current.size === 0) {
                   setTimeout(() => {
                      if (activeSourcesRef.current.size === 0) closeSession();
                   }, 1000);
                }
              }
            }
          }

          const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (audioData && outputAudioContextRef.current && isVoiceActiveRef.current) {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContextRef.current.currentTime);
            const buffer = await decodeAudioData(base64ToUint8Array(audioData), outputAudioContextRef.current, 24000, 1);
            const source = outputAudioContextRef.current.createBufferSource();
            source.buffer = buffer;
            source.connect(outputAudioContextRef.current.destination);
            source.addEventListener('ended', () => { 
              activeSourcesRef.current.delete(source);
              if (isPendingBookingModalRef.current && activeSourcesRef.current.size === 0) {
                isPendingBookingModalRef.current = false; setShowConfirmModal(true); setIsAgentSpeaking(false);
              }
              if (isPendingTerminationRef.current && activeSourcesRef.current.size === 0) setTimeout(closeSession, 200);
            });
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += buffer.duration;
            activeSourcesRef.current.add(source);
          }

          if (msg.serverContent?.interrupted) stopAllAudio();

          if (msg.serverContent?.inputTranscription) {
            const partialText = msg.serverContent.inputTranscription.text;
            userTranscriptionRef.current += partialText;
            checkSecretPhrase(userTranscriptionRef.current);
          }

          if (msg.serverContent?.outputTranscription) modelTranscriptionRef.current += msg.serverContent.outputTranscription.text;

          if (msg.serverContent?.turnComplete) {
            if (userTranscriptionRef.current) { addMessage('user', userTranscriptionRef.current); userTranscriptionRef.current = ""; }
            if (modelTranscriptionRef.current) { addMessage('agent', modelTranscriptionRef.current); modelTranscriptionRef.current = ""; }
          }
        },
        onerror: (err: any) => { 
            console.error("Gemini Error:", err);
            setErrorState("AI Service unavailable."); 
            setIsConnecting(false); 
            cleanupAudioNodes(); 
        },
        onclose: () => { 
            isSessionLiveRef.current = false; 
            setIsConnecting(false); 
            cleanupAudioNodes(); 
        }
      }, teamNames);

      sessionPromise.catch((err) => {
          console.error("Connection failed", err);
          setErrorState("Connection failed");
          setIsConnecting(false);
          cleanupAudioNodes();
      });
      sessionPromiseRef.current = sessionPromise;
    } catch (err) {
      console.error("Start Session Error:", err);
      setErrorState("Failed to connect.");
      setIsConnecting(false);
      cleanupAudioNodes();
    }
  };

  const toggleOpen = () => { if (isOpen) closeSession(); else { setIsOpen(true); setIsVoiceMode(true); startSession(); } };

  const handleChatSubmit = async () => {
    if (!inputText.trim()) return;
    const msg = inputText; setInputText(""); addMessage('user', msg);
    if (isVoiceMode) { setIsVoiceMode(false); stopAllAudio(); cleanupAudioNodes(); }
    try {
      const response = await generateChatResponse(msg, chatHistoryRef.current, teamNames);
      addMessage('agent', response.text);
    } catch (err) { addMessage('agent', "I'm having trouble connecting."); }
  };

  const handleModalConfirm = async () => {
    onNewBooking(pendingBooking);
    setShowConfirmModal(false);
    if (sessionPromiseRef.current && pendingBooking.toolCallId) {
      sessionPromiseRef.current.then((session) => {
        session.sendToolResponse({ functionResponses: [{ id: pendingBooking.toolCallId, name: "requestBookingConfirmation", response: { result: "Success." } }] });
      });
    } else { addMessage('agent', "Perfect! Appointment booked."); }
  };

  const handleModalCancel = () => {
    setShowConfirmModal(false);
    if (sessionPromiseRef.current && pendingBooking.toolCallId) {
      sessionPromiseRef.current.then((session) => {
        session.sendToolResponse({ functionResponses: [{ id: pendingBooking.toolCallId, name: "requestBookingConfirmation", response: { result: "User cancelled." } }] });
      });
    }
  };

  return (
    <>
      <div className="fixed bottom-8 right-8 z-[60] flex flex-col items-end gap-2">
        {!isOpen && (
          <div className="bg-white px-5 py-2.5 rounded-2xl rounded-br-sm shadow-xl border border-pink-100 animate-in slide-in-from-bottom-4 fade-in duration-700 mb-1 relative group cursor-pointer" onClick={toggleOpen}>
             <p className="font-serif italic font-bold text-pink-600 text-sm whitespace-nowrap pr-1">Hey Love ✨</p>
          </div>
        )}
        <button 
          onClick={toggleOpen}
          className={`w-20 h-20 rounded-full flex items-center justify-center transition-all duration-500 shadow-2xl relative group ${isOpen ? 'bg-slate-900 text-white rotate-90' : 'bg-pink-500 text-white hover:scale-110 hover:shadow-pink-200'}`}
        >
          {isOpen ? <X size={32} /> : <Mic size={32} className="group-hover:animate-pulse" />}
        </button>
      </div>

      {isOpen && (
        <div className="fixed inset-0 md:inset-auto md:bottom-32 md:right-8 z-[60] w-full md:w-[450px] md:h-[700px] bg-white md:rounded-[3rem] shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-12 duration-500 border border-pink-50">
          <div className="p-8 bg-slate-900 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-pink-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-pink-500/20">
                {isVoiceMode ? <Mic size={24} className={isAgentSpeaking ? 'animate-pulse' : ''} /> : <Sparkles size={24} />}
              </div>
              <div>
                <h3 className="font-bold text-lg font-serif italic">Candi's AI Assistant</h3>
                <div className="flex items-center gap-1.5">
                  <div className={`w-1.5 h-1.5 rounded-full ${isConnecting ? 'bg-amber-400 animate-pulse' : 'bg-green-400'}`}></div>
                  <span className="text-[9px] uppercase tracking-widest text-slate-400 font-bold">{isConnecting ? 'Connecting...' : 'Active Now'}</span>
                </div>
              </div>
            </div>
            <button onClick={closeSession} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl transition text-slate-400 hover:text-white">
              <X size={20} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/50 custom-scrollbar">
            {messages.length === 0 && !isConnecting && (
              <div className="text-center py-10 space-y-4">
                <div className="w-16 h-16 bg-pink-100 text-pink-500 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Sparkles size={32} />
                </div>
                <h4 className="text-slate-800 font-bold font-serif italic text-xl">How can I help you, Love?</h4>
                <p className="text-slate-400 text-xs max-w-[200px] mx-auto leading-relaxed">I can book appointments, answer beauty questions, or help with salon info.</p>
              </div>
            )}

            {isConnecting && (
              <div className="flex flex-col items-center justify-center h-full space-y-4">
                <Loader2 className="w-8 h-8 text-pink-500 animate-spin" />
                <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Syncing Voice...</p>
              </div>
            )}

            {messages.map((m) => (
              <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[85%] p-5 rounded-[2rem] text-sm font-medium leading-relaxed ${
                  m.role === 'user' 
                    ? 'bg-pink-600 text-white rounded-tr-none shadow-lg shadow-pink-200' 
                    : 'bg-white text-slate-700 rounded-tl-none shadow-sm border border-slate-100'
                }`}>
                  {renderMessageText(m.text)}
                </div>
              </div>
            ))}
            <div ref={messagesEndRef} />
          </div>

          {errorState && (
            <div className="px-8 py-3 bg-red-50 border-t border-red-100 flex items-center gap-3 text-red-500 text-[10px] font-bold uppercase tracking-wider">
              <AlertTriangle size={14} /> {errorState}
              <button onClick={startSession} className="ml-auto underline">Retry</button>
            </div>
          )}

          <div className="p-6 bg-white border-t border-slate-100 shrink-0">
            <div className="relative flex items-center gap-3">
              <input 
                type="text"
                placeholder="Type a message..."
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleChatSubmit()}
                className="flex-1 bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-sm outline-none focus:border-pink-200 transition-all font-medium pr-14"
              />
              <button 
                onClick={handleChatSubmit}
                disabled={!inputText.trim()}
                className="absolute right-2 p-2.5 bg-pink-600 text-white rounded-xl hover:bg-pink-700 transition disabled:opacity-50 disabled:grayscale shadow-md"
              >
                <Send size={18} />
              </button>
            </div>
            <div className="mt-4 flex justify-between items-center px-1">
               <button 
                  onClick={() => setIsVoiceMode(!isVoiceMode)}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.1em] transition-colors ${isVoiceMode ? 'text-pink-600' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  <div className={`w-2 h-2 rounded-full ${isVoiceMode ? 'bg-pink-600 animate-pulse' : 'bg-slate-300'}`}></div>
                  {isVoiceMode ? 'Voice Mode Active' : 'Enable Voice'}
                </button>
                <span className="text-[9px] text-slate-300 font-bold uppercase tracking-widest">Powered by Gemini 2.5</span>
            </div>
          </div>
        </div>
      )}

      {showConfirmModal && (
        <BookingConfirmationModal 
          booking={pendingBooking} 
          onConfirm={handleModalConfirm} 
          onCancel={handleModalCancel} 
        />
      )}
    </>
  );
};

