const handleError = (error: any, context: string) => {
  // Check for network/fetch errors and handle gracefully
  const msg = error.message || "";
  if (msg.includes("Failed to fetch") || msg.includes("Network request failed") || msg.includes("connection error")) {
    console.warn(`[Supabase] Connection failed for ${context}. Using local data fallback.`);
    return [];
  }

  console.error(`[Supabase Error - ${context}]:`, error.message);
  if (error.code === '42P01') return []; 
  throw error;
};

